1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (count: number, wasAlive: boolean): boolean =>
12	  count === 3 || (count === 2 && wasAlive);
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const alive = new Set(cells.map(keyOf));
16	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
17	  for (const [x, y] of cells) {
18	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
19	      const neighbor: Cell = [x + dx, y + dy];
20	      const key = keyOf(neighbor);
21	      const entry = neighborCounts.get(key);
22	      if (entry) entry.count++;
23	      else neighborCounts.set(key, { cell: neighbor, count: 1 });
24	    }
25	  }
26	  const result: Cell[] = [];
27	  for (const [key, { cell, count }] of neighborCounts) {
28	    if (survives(count, alive.has(key))) result.push(cell);
29	  }
30	  return result;
31	}
