1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single isolated cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (both have only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block stable (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should oscillate a vertical blinker into a horizontal blinker", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(horizontal.sort());
24	  });
25	  it("should bring a dead cell to life when it has exactly 3 neighbors (reproduction)", () => {
26	    // L-shape: (0,1) (1,1) (0,0) — dead cell (1,0) has 3 live neighbors
27	    const input: [number, number][] = [[0, 1], [1, 1], [0, 0]];
28	    const result = nextGeneration(input);
29	    expect(result).toContainEqual([1, 0]);
30	  });
31	  it("should kill a live cell with more than 3 neighbors (overpopulation)", () => {
32	    // 3x3 filled square — center (1,1) has 8 live neighbors
33	    const input: [number, number][] = [
34	      [0, 0], [1, 0], [2, 0],
35	      [0, 1], [1, 1], [2, 1],
36	      [0, 2], [1, 2], [2, 2],
37	    ];
38	    const result = nextGeneration(input);
39	    expect(result).not.toContainEqual([1, 1]);
40	  });
